public TypePair getTypesUnderInequality(JSType that) {
  // unions types
  if (that instanceof UnionType) {
    TypePair p = that.getTypesUnderInequality(this);
    return new TypePair(p.typeB, p.typeA);
  }

  // Handle VOID_TYPE and NULL_TYPE collectively
  if (this.isVoidType() || this.isNullType() || that.isVoidType() || that.isNullType()) {
    return new TypePair(this.isVoidType() || this.isNullType() ? this.getNativeType(JSTypeNative.NO_TYPE) : this,
                        that.isVoidType() || that.isNullType() ? that.getNativeType(JSTypeNative.NO_TYPE) : that);
  }

  // other types
  switch (this.testForEquality(that)) {
    case TRUE:
      return new TypePair(null, null);

    case FALSE:
    case UNKNOWN:
      return new TypePair(this, that);
  }

  // switch case is exhaustive
  throw new IllegalStateException();
}
